import React from 'react';
import './Sidebar.css';
import { Wand2, Home, Folder, Users, Moon } from 'lucide-react';

const Sidebar: React.FC = () => {
  return (
    <div className="sidebar">
      {/* Logo */}
      <div className="logo">
        <Wand2 className="logo-icon" size={20} />
        <span className="logo-text">magicpath</span>
      </div>

      {/* User Profile */}
      <div className="user-profile">
        <div className="user-avatar">
          <span>A</span>
        </div>
        <span className="user-name">Ali Shan</span>
        <button className="dropdown-btn">▼</button>
      </div>

      {/* Navigation */}
      <nav className="nav">
        <a href="#" className="nav-item active">
          <Home className="nav-icon" size={16} />
          <span>Home</span>
        </a>
        <a href="#" className="nav-item">
          <Folder className="nav-icon" size={16} />
          <span>My Files</span>
        </a>
        <a href="#" className="nav-item">
          <Users className="nav-icon" size={16} />
          <span>Shared with Me</span>
        </a>
      </nav>

      {/* Components Counter */}
      <div className="components-counter">
        <div className="counter-bar">
          <div className="counter-fill"></div>
        </div>
        <span className="counter-text">5/5 Components left</span>
      </div>

      {/* Theme Toggle */}
      <button className="theme-toggle">
        <Moon size={16} />
      </button>
    </div>
  );
};

export default Sidebar;
